1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH
9	int eval_err;
10	
11	// Apply a binary op to two scalars
12	int eval_binop_scalar(int op, int a, int b) {
13	    if (op == TOK_PLUS)       return a + b;
14	    if (op == TOK_MINUS)      return a - b;
15	    if (op == TOK_STAR)       return a * b;
16	    if (op == TOK_SLASH) {
17	        if (b == 0) { eval_err = 1; return 0; }
18	        return a / b;
19	    }
20	    eval_err = 1;
21	    return 0;
22	}
23	
24	// Evaluate AST node, return heap index of result array.
25	// On error, sets eval_err and returns -1.
26	int eval(int n) {
27	    if (eval_err) return -1;
28	    if (n < 0 || n >= node_count) {
29	        eval_err = 1;
30	        return -1;
31	    }
32	
33	    int ty = node_type[n];
34	
35	    if (ty == NODE_NUM) {
36	        int r = arr_scalar(node_val[n]);
37	        if (r < 0) { eval_err = 1; return -1; }
38	        return r;
39	    }
40	
41	    if (ty == NODE_VEC) {
42	        return node_val[n];
43	    }
44	
45	    if (ty == NODE_IDENT) {
46	        int idx = node_val[n];
47	        if (!sym_set_flag[idx]) {
48	            eval_err = 2;
49	            return -1;
50	        }
51	        return sym_val[idx];
52	    }
53	
54	    if (ty == NODE_ASSIGN) {
55	        int idx = node_val[n];
56	        int v = eval(node_right[n]);
57	        if (eval_err) return -1;
58	        sym_val[idx] = v;
59	        sym_set_flag[idx] = 1;
60	        return v;
61	    }
62	
63	    if (ty == NODE_QOUT) {
64	        int v = eval(node_right[n]);
65	        if (eval_err) return -1;
66	        return v;
67	    }
68	
69	    if (ty == NODE_NEG) {
70	        int v = eval(node_right[n]);
71	        if (eval_err) return -1;
72	        int rk = arr_rank(v);
73	        if (rk == 0) {
74	            int r = arr_scalar(0 - arr_get(v, 0));
75	            if (r < 0) { eval_err = 1; return -1; }
76	            return r;
77	        }
78	        // Negate each element of vector
79	        if (rk == 1) {
80	            int sz = arr_size(v);
81	            int r = arr_vector(sz);
82	            if (r < 0) { eval_err = 1; return -1; }
83	            int i = 0;
84	            while (i < sz) {
85	                arr_set(r, i, 0 - arr_get(v, i));
86	                i++;
87	            }
88	            return r;
89	        }
90	        // Negate each element of matrix
91	        if (rk == 2) {
92	            int d0 = arr_dim0(v);
93	            int d1 = arr_dim1(v);
94	            int sz = d0 * d1;
95	            int r = arr_new(2, d0, d1);
96	            if (r < 0) { eval_err = 1; return -1; }
97	            int i = 0;
98	            while (i < sz) {
99	                arr_set(r, i, 0 - arr_get(v, i));
100	                i++;
101	            }
102	            return r;
103	        }
104	        eval_err = 1;
105	        return -1;
106	    }
107	
108	    if (ty == NODE_MONAD) {
109	        int v = eval(node_right[n]);
110	        if (eval_err) return -1;
111	        int res_id = node_val[n];
112	
113	        if (res_id == RES_IOTA) {
114	            // iota N: generate vector 0 1 2 ... N-1
115	            if (arr_rank(v) != 0) { eval_err = 3; return -1; }
116	            int count = arr_get(v, 0);
117	            if (count < 0) { eval_err = 1; return -1; }
118	            int r = arr_vector(count);
119	            if (r < 0) { eval_err = 1; return -1; }
120	            int i = 0;
121	            while (i < count) {
122	                arr_set(r, i, i);
123	                i++;
124	            }
125	            return r;
126	        }
127	
128	        if (res_id == RES_RHO) {
129	            // rho A: return shape of A
130	            int rk = arr_rank(v);
131	            if (rk == 0) {
132	                // Scalar: shape is empty vector
133	                int r = arr_vector(0);
134	                if (r < 0) { eval_err = 1; return -1; }
135	                return r;
136	            }
137	            if (rk == 1) {
138	                // Vector: shape is 1-element vector with length
139	                int r = arr_scalar(arr_dim0(v));
140	                if (r < 0) { eval_err = 1; return -1; }
141	                return r;
142	            }
143	            if (rk == 2) {
144	                // Matrix: shape is 2-element vector (rows cols)
145	                int r = arr_vector(2);
146	                if (r < 0) { eval_err = 1; return -1; }
147	                arr_set(r, 0, arr_dim0(v));
148	                arr_set(r, 1, arr_dim1(v));
149	                return r;
150	            }
151	            eval_err = 1;
152	            return -1;
153	        }
154	
155	        if (res_id == RES_REV) {
156	            // rev A: reverse a vector
157	            int rk = arr_rank(v);
158	            if (rk == 0) {
159	                // Scalar: reverse is identity
160	                return v;
161	            }
162	            if (rk == 1) {
163	                int sz = arr_size(v);
164	                int r = arr_vector(sz);
165	                if (r < 0) { eval_err = 1; return -1; }
166	                int i = 0;
167	                while (i < sz) {
168	                    arr_set(r, i, arr_get(v, sz - 1 - i));
169	                    i++;
170	                }
171	                return r;
172	            }
173	            eval_err = 1;
174	            return -1;
175	        }
176	
177	        if (res_id == RES_CAT) {
178	            // Monadic cat: ravel (flatten to 1D vector)
179	            int rk = arr_rank(v);
180	            if (rk == 0) {
181	                // Scalar -> 1-element vector
182	                int r = arr_vector(1);
183	                if (r < 0) { eval_err = 1; return -1; }
184	                arr_set(r, 0, arr_get(v, 0));
185	                return r;
186	            }
187	            if (rk == 1) {
188	                // Vector: already 1D, return as-is
189	                return v;
190	            }
191	            if (rk == 2) {
192	                // Matrix -> vector of all elements
193	                int sz = arr_size(v);
194	                int r = arr_vector(sz);
195	                if (r < 0) { eval_err = 1; return -1; }
196	                int i = 0;
197	                while (i < sz) {
198	                    arr_set(r, i, arr_get(v, i));
199	                    i++;
200	                }
201	                return r;
202	            }
203	            eval_err = 1;
204	            return -1;
205	        }
206	
207	        // Unknown monadic function
208	        eval_err = 1;
209	        return -1;
210	    }
211	
212	    if (ty == NODE_REDUCE) {
213	        int v = eval(node_right[n]);
214	        if (eval_err) return -1;
215	        int op = node_val[n];
216	        int rk = arr_rank(v);
217	
218	        // Scalar reduce: just return the scalar
219	        if (rk == 0) {
220	            return v;
221	        }
222	
223	        // Vector reduce: right-to-left fold
224	        if (rk == 1) {
225	            int sz = arr_size(v);
226	            if (sz == 0) { eval_err = 1; return -1; }
227	            int acc = arr_get(v, sz - 1);
228	            int i = sz - 2;
229	            while (i >= 0) {
230	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
231	                if (eval_err) return -1;
232	                i--;
233	            }
234	            int r = arr_scalar(acc);
235	            if (r < 0) { eval_err = 1; return -1; }
236	            return r;
237	        }
238	
239	        // Unsupported rank
240	        eval_err = 1;
241	        return -1;
242	    }
243	
244	    if (ty == NODE_DYAD) {
245	        int lv = eval(node_left[n]);
246	        if (eval_err) return -1;
247	        int rv = eval(node_right[n]);
248	        if (eval_err) return -1;
249	        int res_id = node_val[n];
250	
251	        if (res_id == RES_RHO) {
252	            // S rho A: reshape A to shape S with cyclic fill
253	            // S is scalar -> result is vector of that length
254	            // S is 2-element vector -> result is matrix
255	            int lrk = arr_rank(lv);
256	            int new_rank;
257	            int d0;
258	            int d1;
259	
260	            if (lrk == 0) {
261	                // Scalar shape -> vector
262	                new_rank = 1;
263	                d0 = arr_get(lv, 0);
264	                d1 = 0;
265	                if (d0 < 0) { eval_err = 1; return -1; }
266	            } else if (lrk == 1) {
267	                int lsz = arr_size(lv);
268	                if (lsz == 1) {
269	                    new_rank = 1;
270	                    d0 = arr_get(lv, 0);
271	                    d1 = 0;
272	                    if (d0 < 0) { eval_err = 1; return -1; }
273	                } else if (lsz == 2) {
274	                    new_rank = 2;
275	                    d0 = arr_get(lv, 0);
276	                    d1 = arr_get(lv, 1);
277	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
278	                } else {
279	                    // Only rank 1 and 2 supported
280	                    eval_err = 1;
281	                    return -1;
282	                }
283	            } else {
284	                eval_err = 1;
285	                return -1;
286	            }
287	
288	            int r = arr_new(new_rank, d0, d1);
289	            if (r < 0) { eval_err = 1; return -1; }
290	
291	            int total = arr_size(r);
292	            int src_sz = arr_size(rv);
293	            if (src_sz == 0) { eval_err = 1; return -1; }
294	
295	            int i = 0;
296	            while (i < total) {
297	                arr_set(r, i, arr_get(rv, i % src_sz));
298	                i++;
299	            }
300	            return r;
301	        }
302	
303	        if (res_id == RES_TAKE) {
304	            // N take A: take first N elements (negative N = from end)
305	            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
306	            int count = arr_get(lv, 0);
307	            int sz = arr_size(rv);
308	            int abs_n = count;
309	            if (abs_n < 0) abs_n = 0 - abs_n;
310	            if (abs_n > sz) { eval_err = 3; return -1; }
311	
312	            int r = arr_vector(abs_n);
313	            if (r < 0) { eval_err = 1; return -1; }
314	            int start = 0;
315	            if (count < 0) start = sz - abs_n;
316	            int i = 0;
317	            while (i < abs_n) {
318	                arr_set(r, i, arr_get(rv, start + i));
319	                i++;
320	            }
321	            return r;
322	        }
323	
324	        if (res_id == RES_DROP) {
325	            // N drop A: drop first N elements (negative N = from end)
326	            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
327	            int count = arr_get(lv, 0);
328	            int sz = arr_size(rv);
329	            int abs_n = count;
330	            if (abs_n < 0) abs_n = 0 - abs_n;
331	            if (abs_n > sz) abs_n = sz;
332	
333	            int new_sz = sz - abs_n;
334	            int r = arr_vector(new_sz);
335	            if (r < 0) { eval_err = 1; return -1; }
336	            int start = abs_n;
337	            if (count < 0) start = 0;
338	            int i = 0;
339	            while (i < new_sz) {
340	                arr_set(r, i, arr_get(rv, start + i));
341	                i++;
342	            }
343	            return r;
344	        }
345	
346	        if (res_id == RES_CAT) {
347	            // Dyadic cat: catenate two arrays
348	            int lrk = arr_rank(lv);
349	            int rrk = arr_rank(rv);
350	            int lsz = arr_size(lv);
351	            int rsz = arr_size(rv);
352	            int total = lsz + rsz;
353	            int r = arr_vector(total);
354	            if (r < 0) { eval_err = 1; return -1; }
355	            int i = 0;
356	            while (i < lsz) {
357	                arr_set(r, i, arr_get(lv, i));
358	                i++;
359	            }
360	            i = 0;
361	            while (i < rsz) {
362	                arr_set(r, lsz + i, arr_get(rv, i));
363	                i++;
364	            }
365	            return r;
366	        }
367	
368	        // Unknown dyadic function
369	        eval_err = 1;
370	        return -1;
371	    }
372	
373	    if (ty == NODE_BINOP) {
374	        int lv = eval(node_left[n]);
375	        if (eval_err) return -1;
376	        int rv = eval(node_right[n]);
377	        if (eval_err) return -1;
378	
379	        int lrk = arr_rank(lv);
380	        int rrk = arr_rank(rv);
381	        int op = node_val[n];
382	
383	        // Scalar op scalar
384	        if (lrk == 0 && rrk == 0) {
385	            int result = eval_binop_scalar(op, arr_get(lv, 0), arr_get(rv, 0));
386	            if (eval_err) return -1;
387	            int r = arr_scalar(result);
388	            if (r < 0) { eval_err = 1; return -1; }
389	            return r;
390	        }
391	
392	        // Vector op vector: must match length
393	        if (lrk == 1 && rrk == 1) {
394	            int lsz = arr_size(lv);
395	            int rsz = arr_size(rv);
396	            if (lsz != rsz) { eval_err = 3; return -1; }
397	            int r = arr_vector(lsz);
398	            if (r < 0) { eval_err = 1; return -1; }
399	            int i = 0;
400	            while (i < lsz) {
401	                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
402	                if (eval_err) return -1;
403	                arr_set(r, i, val);
404	                i++;
405	            }
406	            return r;
407	        }
408	
409	        // Scalar op vector
410	        if (lrk == 0 && rrk == 1) {
411	            int la = arr_get(lv, 0);
412	            int rsz = arr_size(rv);
413	            int r = arr_vector(rsz);
414	            if (r < 0) { eval_err = 1; return -1; }
415	            int i = 0;
416	            while (i < rsz) {
417	                int val = eval_binop_scalar(op, la, arr_get(rv, i));
418	                if (eval_err) return -1;
419	                arr_set(r, i, val);
420	                i++;
421	            }
422	            return r;
423	        }
424	
425	        // Vector op scalar
426	        if (lrk == 1 && rrk == 0) {
427	            int ra = arr_get(rv, 0);
428	            int lsz = arr_size(lv);
429	            int r = arr_vector(lsz);
430	            if (r < 0) { eval_err = 1; return -1; }
431	            int i = 0;
432	            while (i < lsz) {
433	                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
434	                if (eval_err) return -1;
435	                arr_set(r, i, val);
436	                i++;
437	            }
438	            return r;
439	        }
440	
441	        // Matrix op matrix: must match shape
442	        if (lrk == 2 && rrk == 2) {
443	            if (arr_dim0(lv) != arr_dim0(rv) || arr_dim1(lv) != arr_dim1(rv)) {
444	                eval_err = 3; return -1;
445	            }
446	            int d0 = arr_dim0(lv);
447	            int d1 = arr_dim1(lv);
448	            int r = arr_new(2, d0, d1);
449	            if (r < 0) { eval_err = 1; return -1; }
450	            int sz = d0 * d1;
451	            int i = 0;
452	            while (i < sz) {
453	                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
454	                if (eval_err) return -1;
455	                arr_set(r, i, val);
456	                i++;
457	            }
458	            return r;
459	        }
460	
461	        // Scalar op matrix
462	        if (lrk == 0 && rrk == 2) {
463	            int la = arr_get(lv, 0);
464	            int d0 = arr_dim0(rv);
465	            int d1 = arr_dim1(rv);
466	            int r = arr_new(2, d0, d1);
467	            if (r < 0) { eval_err = 1; return -1; }
468	            int sz = d0 * d1;
469	            int i = 0;
470	            while (i < sz) {
471	                int val = eval_binop_scalar(op, la, arr_get(rv, i));
472	                if (eval_err) return -1;
473	                arr_set(r, i, val);
474	                i++;
475	            }
476	            return r;
477	        }
478	
479	        // Matrix op scalar
480	        if (lrk == 2 && rrk == 0) {
481	            int ra = arr_get(rv, 0);
482	            int d0 = arr_dim0(lv);
483	            int d1 = arr_dim1(lv);
484	            int r = arr_new(2, d0, d1);
485	            if (r < 0) { eval_err = 1; return -1; }
486	            int sz = d0 * d1;
487	            int i = 0;
488	            while (i < sz) {
489	                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
490	                if (eval_err) return -1;
491	                arr_set(r, i, val);
492	                i++;
493	            }
494	            return r;
495	        }
496	
497	        // Unsupported rank combination
498	        eval_err = 1;
499	        return -1;
500	    }
501	
502	    eval_err = 1;
503	    return -1;
504	}
